const input = $input.first().json;

// 尽可能兼容不同 AI 节点的输出格式
let raw =
  input.output ||
  input.text ||
  input.response ||
  input.message ||
  input.content ||
  input.choices?.[0]?.message?.content ||
  '';

// 如果 message 是对象，尝试取 content
if (typeof raw === 'object' && raw.content) {
  raw = raw.content;
}

// 如果仍然不是字符串，转成字符串
if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

// 去掉可能出现的 markdown 代码块
raw = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  // 如果模型没有严格输出 JSON，就退化为普通关键词
  parsed = {
    queries: [raw],
    recommended_query: raw
  };
}

const queries = parsed.queries || [];
const recommendedQuery = parsed.recommended_query || queries[0] || 'AI protein design';

return [
  {
    json: {
      query: recommendedQuery,
      all_queries: queries,
      question: $('标准化用户输入').first().json.question,
      domain: $('标准化用户输入').first().json.domain,
      max_papers: $('标准化用户输入').first().json.max_papers,
      output_language: $('标准化用户输入').first().json.output_language,
      task_name: $('标准化用户输入').first().json.task_name,
      year_from: $('标准化用户输入').first().json.year_from,
      year_to: $('标准化用户输入').first().json.year_to
    }
  }
];

 const response = $input.first().json;
const works = response.results || [];

const context = $('解析检索式').first().json;

// OpenAlex 的 abstract 通常是 abstract_inverted_index，需要还原成普通文本
function reconstructAbstract(invertedIndex) {
  if (!invertedIndex || typeof invertedIndex !== 'object') {
    return '';
  }

  const words = [];

  for (const [word, positions] of Object.entries(invertedIndex)) {
    if (Array.isArray(positions)) {
      for (const pos of positions) {
        words.push([pos, word]);
      }
    }
  }

  return words
    .sort((a, b) => a[0] - b[0])
    .map(item => item[1])
    .join(' ');
}

return works.map((work, index) => {
  const authors = (work.authorships || [])
    .map(a => a.author?.display_name)
    .filter(Boolean)
    .join(', ');

  const venue =
    work.primary_location?.source?.display_name ||
    work.host_venue?.display_name ||
    '';

  const url =
    work.doi ||
    work.primary_location?.landing_page_url ||
    work.id ||
    '';

  const concepts = (work.concepts || [])
    .slice(0, 5)
    .map(c => c.display_name)
    .filter(Boolean)
    .join(', ');

  const openalexId = (work.id || '').replace('https://openalex.org/', '');

  return {
    json: {
      rank: index + 1,
      paper_id: work.id || '',
      openalex_id: openalexId,
      title: work.display_name || '',
      abstract: reconstructAbstract(work.abstract_inverted_index),
      year: work.publication_year || '',
      publication_date: work.publication_date || '',
      authors,
      venue,
      citation_count: work.cited_by_count || 0,
      doi: work.doi || '',
      url,
      concepts,

      // 新增：用于引文溯源和雪球法
      referenced_works: work.referenced_works || [],
      cited_by_api_url: work.cited_by_api_url || '',
      related_works: work.related_works || [],

      // 新增：记录文献来源
      source_database: 'OpenAlex',
      source_type: 'initial_search',
      parent_seed_title: '',
      parent_seed_id: '',

      // 保留上游任务信息，方便后续 AI 分析
      query: context.query,
      question: context.question,
      domain: context.domain,
      max_papers: context.max_papers,
      output_language: context.output_language,
      task_name: context.task_name,
      year_from: context.year_from,
      year_to: context.year_to
    }
  };
});

const input = $input.first().json;

// 兼容 n8n XML 节点的不同输出结构
const feed = input.feed || input.data?.feed || input;
let entries = feed.entry || [];

if (!entries) {
  return [];
}

if (!Array.isArray(entries)) {
  entries = [entries];
}

const context = $('解析检索式').first().json;

function getText(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (value._) return value._;
  if (value['#text']) return value['#text'];
  return String(value);
}

function getAuthors(authorField) {
  if (!authorField) return '';
  const authors = Array.isArray(authorField) ? authorField : [authorField];
  return authors.map(a => getText(a.name)).filter(Boolean).join(', ');
}

function getYear(published) {
  const text = getText(published);
  return text ? text.slice(0, 4) : '';
}

function getPdfUrl(entry) {
  const links = Array.isArray(entry.link) ? entry.link : [entry.link].filter(Boolean);
  const pdf = links.find(l => l.$?.title === 'pdf' || l.$?.type === 'application/pdf');
  return pdf?.$?.href || getText(entry.id);
}

function getArxivId(entry) {
  const id = getText(entry.id);
  return id
    .replace('http://arxiv.org/abs/', '')
    .replace('https://arxiv.org/abs/', '');
}

return entries.map((entry, index) => ({
  json: {
    rank: index + 1,
    paper_id: getText(entry.id),
    openalex_id: '',
    arxiv_id: getArxivId(entry),
    title: getText(entry.title).replace(/\s+/g, ' ').trim(),
    abstract: getText(entry.summary).replace(/\s+/g, ' ').trim(),
    year: getYear(entry.published),
    publication_date: getText(entry.published),
    authors: getAuthors(entry.author),
    venue: 'arXiv',
    citation_count: 0,
    doi: '',
    url: getPdfUrl(entry),
    concepts: 'arXiv preprint',

    // arXiv 没有 OpenAlex 引文网络字段，先置空
    referenced_works: [],
    cited_by_api_url: '',
    related_works: [],

    // 标记来源
    source_database: 'arXiv',
    source_type: 'arxiv_search',
    parent_seed_title: '',
    parent_seed_id: '',

    // 保留上游任务信息
    query: context.query,
    question: context.question,
    domain: context.domain,
    max_papers: context.max_papers,
    output_language: context.output_language,
    task_name: context.task_name,
    year_from: context.year_from,
    year_to: context.year_to
  }
}));

const items = $input.all().map(item => item.json);

const seen = new Set();
const output = [];

function normalizeTitle(title) {
  return String(title || '')
    .toLowerCase()
    .replace(/<[^>]*>/g, '')
    .replace(/[^\p{L}\p{N}\s]/gu, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeDoi(doi) {
  return String(doi || '')
    .toLowerCase()
    .replace('https://doi.org/', '')
    .replace('http://doi.org/', '')
    .trim();
}

for (const paper of items) {
  const doiKey = normalizeDoi(paper.doi);
  const titleKey = normalizeTitle(paper.title);
  const arxivKey = String(paper.arxiv_id || '').toLowerCase().trim();
  const openalexKey = String(paper.openalex_id || '').toLowerCase().trim();
  const paperKey = String(paper.paper_id || '').toLowerCase().trim();

  const keys = [
    doiKey ? `doi:${doiKey}` : '',
    titleKey ? `title:${titleKey}` : '',
    arxivKey ? `arxiv:${arxivKey}` : '',
    openalexKey ? `openalex:${openalexKey}` : '',
    paperKey ? `paper:${paperKey}` : ''
  ].filter(Boolean);

  if (keys.length === 0) continue;

  const isDuplicate = keys.some(k => seen.has(k));

  if (!isDuplicate) {
    keys.forEach(k => seen.add(k));
    output.push({
      json: {
        ...paper,
        dedup_key: keys[0],
        normalized_title: titleKey
      }
    });
  }
}

return output;

