const screeningItems = $input.all();
const paperItems = $('去重文献-多源检索').all();

function getRawOutput(json) {
  let raw =
    json.output ||
    json.text ||
    json.response ||
    json.message ||
    json.content ||
    json.result ||
    json.choices?.[0]?.message?.content ||
    '';

  if (typeof raw === 'object' && raw.content) {
    raw = raw.content;
  }

  if (typeof raw !== 'string') {
    raw = JSON.stringify(raw);
  }

  return raw.trim();
}

function cleanJsonText(raw) {
  return raw
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();
}

function extractJson(raw) {
  const cleaned = cleanJsonText(raw);

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const start = cleaned.indexOf('{');
    const end = cleaned.lastIndexOf('}');
    if (start !== -1 && end !== -1 && end > start) {
      const possibleJson = cleaned.slice(start, end + 1);
      try {
        return JSON.parse(possibleJson);
      } catch (e2) {
        return null;
      }
    }
    return null;
  }
}

return screeningItems.map((item, index) => {
  const raw = getRawOutput(item.json);
  const parsed = extractJson(raw);

  const originalPaper = paperItems[index]?.json || {};

  let decision = parsed?.decision || 'exclude';
  decision = String(decision).toLowerCase().trim();

  if (!['include', 'exclude'].includes(decision)) {
    decision = decision.includes('include') || decision.includes('保留') ? 'include' : 'exclude';
  }

  let score = Number(parsed?.score ?? 0);
  if (Number.isNaN(score)) {
    score = 0;
  }

  return {
    json: {
      ...originalPaper,

      screen_decision: decision,
      screen_score: score,
      screen_reason: parsed?.reason || '',
      evidence_type: parsed?.evidence_type || '',
      relation_to_question: parsed?.relation_to_question || '',
      screening_raw_output: raw
    }
  };
});

const papers = $('解析初筛结果').all().map(item => item.json);

