// 只把 AI 二次筛选认为比较相关的文献交给人类复核
// include 全部保留；如果不是 include，但分数 >= 70，也进入人工候选，避免漏掉边界文献
const candidates = papers
  .filter(paper => {
    const decision = String(paper.final_screen_decision || '').toLowerCase().trim();
    const score = Number(paper.final_screen_score || 0);
    return decision === 'include' || score >= 70;
  })
  .sort((a, b) => Number(b.final_screen_score || 0) - Number(a.final_screen_score || 0))
  .map((paper, index) => {
    const reviewId = index + 1;

    return {
      ...paper,
      review_id: reviewId
    };
  });

function shortText(text, maxLen = 350) {
  const s = String(text || '').replace(/\s+/g, ' ').trim();
  if (!s) return '无摘要信息';
  return s.length > maxLen ? s.slice(0, maxLen) + '...' : s;
}

const reviewLines = [];

reviewLines.push('# 人工复核候选文献列表');
reviewLines.push('');
reviewLines.push('请阅读下面的候选文献，并在下一步表单中输入你希望保留的文献序号。');
reviewLines.push('');
reviewLines.push('输入示例：');
reviewLines.push('');
reviewLines.push('```');
reviewLines.push('1,3,5,8');
reviewLines.push('```');
reviewLines.push('');
reviewLines.push('如果你想全部保留，可以输入：');
reviewLines.push('');
reviewLines.push('```');
reviewLines.push('all');
reviewLines.push('```');
reviewLines.push('');
reviewLines.push('---');
reviewLines.push('');

for (const paper of candidates) {
  reviewLines.push(`## ${paper.review_id}. ${paper.title || '无标题'}`);
  reviewLines.push('');
  reviewLines.push(`- 年份：${paper.year || '未知'}`);
  reviewLines.push(`- 来源数据库：${paper.source_database || '未知'}`);
  reviewLines.push(`- 来源类型：${paper.source_type || '未知'}`);
  reviewLines.push(`- 雪球/溯源种子文献：${paper.parent_seed_title || '无'}`);
  reviewLines.push(`- AI 二次筛选结果：${paper.final_screen_decision || '未知'}`);
  reviewLines.push(`- AI 二次筛选分数：${paper.final_screen_score ?? '未知'}`);
  reviewLines.push(`- AI 筛选理由：${paper.final_screen_reason || '未提供'}`);
  reviewLines.push('');
  reviewLines.push(`摘要片段：${shortText(paper.abstract)}`);
  reviewLines.push('');
  reviewLines.push('---');
  reviewLines.push('');
}

return [
  {
    json: {
      task_name: candidates[0]?.task_name || papers[0]?.task_name || '',
      question: candidates[0]?.question || papers[0]?.question || '',
      domain: candidates[0]?.domain || papers[0]?.domain || '',
      output_language: candidates[0]?.output_language || papers[0]?.output_language || '中文',

      review_candidate_count: candidates.length,
      review_summary_markdown: reviewLines.join('\n'),
      review_candidates: candidates,

      human_review_instruction: '请在下一步输入要保留的文献序号，例如：1,3,5,8；如果全部保留，输入 all。'
    }
  }
];

const waitOutput = $input.first().json;

// 从 Prepare Human Review Summary 取候选文献列表
const reviewData = $('准备人工复核摘要').first().json;
const candidates = reviewData.review_candidates || [];

// 兼容不同 n8n 版本中 Wait 表单输出字段的位置
const rawKeepIds =
  waitOutput.human_keep_ids ||
  waitOutput.data?.human_keep_ids ||
  waitOutput.formData?.human_keep_ids ||
  waitOutput.body?.human_keep_ids ||
  '';

const humanReviewNote =
  waitOutput.human_review_note ||
  waitOutput.data?.human_review_note ||
  waitOutput.formData?.human_review_note ||
  waitOutput.body?.human_review_note ||
  '';

function parseKeepIds(raw) {
  const text = String(raw || '').trim();

  if (!text) {
    return new Set();
  }

  if (text.toLowerCase() === 'all' || text === '全部') {
    return 'all';
  }

  const ids = text
    .replace(/，/g, ',')
    .split(',')
    .map(x => Number(String(x).trim()))
    .filter(x => Number.isFinite(x) && x > 0);

  return new Set(ids);
}

const keepIds = parseKeepIds(rawKeepIds);

let selected = [];

if (keepIds === 'all') {
  selected = candidates;
} else {
  selected = candidates.filter(paper => keepIds.has(Number(paper.review_id)));
}

return selected.map((paper, index) => ({
  json: {
    ...paper,

    // 人工复核信息
    human_review_decision: 'include',
    human_review_rank: index + 1,
    human_keep_ids: rawKeepIds,
    human_review_note: humanReviewNote,

    // 为了兼容后续节点，也把最终筛选结果统一改成人工确认后的 include
    final_screen_decision: 'include',
    final_screen_score: paper.final_screen_score || paper.screen_score || '',
    final_screen_reason:
      paper.final_screen_reason ||
      paper.screen_reason ||
      '人工复核后保留'
  }
}));

