const evidenceItems = $input.all();
const includedPapers = $('应用人工复核结果').all();

function getRawOutput(json) {
  let raw =
    json.output ||
    json.text ||
    json.response ||
    json.message ||
    json.content ||
    json.result ||
    json.choices?.[0]?.message?.content ||
    '';

  if (typeof raw === 'object' && raw.content) {
    raw = raw.content;
  }

  if (typeof raw !== 'string') {
    raw = JSON.stringify(raw);
  }

  return raw.trim();
}

function cleanJsonText(raw) {
  return raw
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();
}

function extractJson(raw) {
  const cleaned = cleanJsonText(raw);

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const start = cleaned.indexOf('{');
    const end = cleaned.lastIndexOf('}');
    if (start !== -1 && end !== -1 && end > start) {
      const possibleJson = cleaned.slice(start, end + 1);
      try {
        return JSON.parse(possibleJson);
      } catch (e2) {
        return null;
      }
    }
    return null;
  }
}

function toText(value) {
  if (Array.isArray(value)) {
    return value.join('；');
  }
  if (value && typeof value === 'object') {
    return JSON.stringify(value, null, 2);
  }
  return value || '';
}

return evidenceItems.map((item, index) => {
  const raw = getRawOutput(item.json);
  const parsed = extractJson(raw);

  const originalPaper = includedPapers[index]?.json || {};

  return {
    json: {
      // 原始论文信息
      rank: originalPaper.rank || index + 1,
      paper_id: originalPaper.paper_id || '',
      title: originalPaper.title || parsed?.title || '',
      authors: originalPaper.authors || '',
      year: originalPaper.year || parsed?.year || '',
      venue: originalPaper.venue || '',
      citation_count: originalPaper.citation_count || 0,
      doi: originalPaper.doi || '',
      url: originalPaper.url || '',
      concepts: originalPaper.concepts || '',
      abstract: originalPaper.abstract || '',

      // 筛选信息
      screen_decision: originalPaper.screen_decision || '',
      screen_score: originalPaper.screen_score || '',
      screen_reason: originalPaper.screen_reason || '',
      evidence_type: originalPaper.evidence_type || '',
      relation_to_question: originalPaper.relation_to_question || '',

      // 证据卡片信息
      research_problem: parsed?.research_problem || '',
      method: parsed?.method || '',
      main_contribution: parsed?.main_contribution || '',
      key_findings: toText(parsed?.key_findings),
      limitations: toText(parsed?.limitations),
      usable_evidence: toText(parsed?.usable_evidence),
   reported_limitations: parsed?.reported_limitations || '',
open_issues_for_manual_check: parsed?.open_issues_for_manual_check || '',
      relation_to_user_question: parsed?.relation_to_user_question || '',

      // 上游任务信息
      query: originalPaper.query || '',
      question: originalPaper.question || '',
      domain: originalPaper.domain || '',
      output_language: originalPaper.output_language || '中文',
      task_name: originalPaper.task_name || '',

      // 便于调试
      evidence_raw_output: raw,

      //来源
      source_database: originalPaper.source_database || '',
      source_type: originalPaper.source_type || '',
      parent_seed_title: originalPaper.parent_seed_title || '',
      parent_seed_id: originalPaper.parent_seed_id || '',
      openalex_id: originalPaper.openalex_id || '',
      arxiv_id: originalPaper.arxiv_id || '',
      dedup_key: originalPaper.dedup_key || '',
    }
  };
});

const cards = $input.all().map(item => item.json);

const first = cards[0] || {};

function safeCount(nodeName) {
  try {
    return $(nodeName).all().length;
  } catch (e) {
    return 0;
  }
}

function countBy(items, field) {
  const stats = {};
  for (const item of items) {
    const key = item[field] || 'unknown';
    stats[key] = (stats[key] || 0) + 1;
  }
  return stats;
}

const evidenceCards = cards.map((card, index) => ({
  index: index + 1,
  title: card.title || '',
  authors: card.authors || '',
  year: card.year || '',
  venue: card.venue || '',
  citation_count: card.citation_count || 0,
  url: card.url || '',
  doi: card.doi || '',
  source_database: card.source_database || '',
  source_type: card.source_type || '',
  parent_seed_title: card.parent_seed_title || '',
  screen_score: card.screen_score || card.final_screen_score || '',
  screen_reason: card.screen_reason || card.final_screen_reason || '',
  research_problem: card.research_problem || '',
  method: card.method || '',
  main_contribution: card.main_contribution || '',
  key_findings: card.key_findings || '',
  limitations: card.limitations || '',
  usable_evidence: card.usable_evidence || '',
  reported_limitations: card.reported_limitations || '',
  open_issues_for_manual_check: card.open_issues_for_manual_check || '',
  relation_to_user_question: card.relation_to_user_question || ''
}));

const sourceStats = {
  by_database: countBy(evidenceCards, 'source_database'),
  by_source_type: countBy(evidenceCards, 'source_type')
};

return [
  {
    json: {
      task_name: first.task_name || 'AI驱动蛋白质结构设计文献自动理解',
      question: first.question || '',
      domain: first.domain || '',
      query: first.query || '',
      output_language: first.output_language || '中文',
      selected_paper_count: evidenceCards.length,
      evidence_cards: evidenceCards,

      database_construction: {
        openalex_arxiv_merged_count: safeCount('Merge OpenAlex and arXiv Papers'),
        multi_source_deduplicated_count: safeCount('Deduplicate Multi-source Papers'),
        first_round_included_count: safeCount('Keep Included Papers'),
        forward_snowball_candidate_count: safeCount('Normalize Citing Papers'),
        backward_snowball_candidate_count: safeCount('Normalize Referenced Works'),
        expanded_merged_count: safeCount('Merge Original and Snowball Papers'),
        expanded_deduplicated_count: safeCount('Deduplicate Papers'),
        final_selected_count: evidenceCards.length,
        final_source_statistics: sourceStats
      }
    }
  }
];

const input = $input.first().json;

function getReportText(json) {
  let raw =
    json.output ||
    json.text ||
    json.response ||
    json.message ||
    json.content ||
    json.result ||
    json.choices?.[0]?.message?.content ||
    '';

  if (typeof raw === 'object' && raw.content) {
    raw = raw.content;
  }

  if (typeof raw !== 'string') {
    raw = JSON.stringify(raw, null, 2);
  }

  return raw.trim();
}

const markdown = getReportText(input);

const now = new Date();
const dateStr = now.toISOString().slice(0, 10);

const filename = `AI驱动蛋白质结构设计文献自动理解报告_${dateStr}.md`;

return [
  {
    json: {
      filename,
      markdown_report: markdown,
      email_subject: `AI驱动蛋白质设计科学文献自动理解报告 - ${dateStr}`,
      email_body: `您好，\n\n附件中是本次 n8n 自动化科研工作流生成的 Markdown 报告。\n\n报告主题：AI驱动蛋白质设计科学文献自动理解\n\n此报告由以下流程自动生成：\n问题输入 → 检索式生成 → 文献检索 → 文献筛选 → 证据卡片生成 → 科学文献自动理解 → Markdown 报告输出。\n\n请查收附件。\n`
    },
    binary: {
      data: {
        data: Buffer.from(markdown, 'utf8').toString('base64'),
        mimeType: 'text/markdown',
        fileName: filename,
        fileExtension: 'md'
      }
    }
  }
];
